import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias predeterminados: atajos esenciales del shell | Dotfiles (ES)","titleTemplate":":title","description":"Alias esenciales para navegación, control del sistema y tareas diarias. Simplifica tu flujo de trabajo.","frontmatter":{"title":"Alias predeterminados: atajos esenciales del shell","description":"Alias esenciales para navegación, control del sistema y tareas diarias. Simplifica tu flujo de trabajo.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias predeterminados: atajos esenciales del shell preview","canonical":"/es/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias predeterminados: atajos esenciales del shell","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias predeterminados | Dotfiles","permalink":"/es/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"alias predeterminados, alias shell, atajos terminal, dotfiles, alias bash"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias predeterminados | Dotfiles"},{"name":"twitter:description","content":"Alias esenciales para navegación, control del sistema y tareas diarias."},{"name":"og:title","content":"Alias predeterminados | Dotfiles"},{"name":"og:description","content":"Alias esenciales para navegación, control del sistema y tareas diarias."},{"name":"og:image:alt","content":"Dotfiles - Diseñado para tu vida en el shell"},{"name":"og:locale","content":"es_ES"}]},"headers":[],"relativePath":"es/aliases/default/index.md","filePath":"es/aliases/default/index.md","lastUpdated":1773010926000}'),i={name:"es/aliases/default/index.md"};function r(s,t,l,c,n,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="alias-predeterminados" tabindex="-1">Alias predeterminados <a class="header-anchor" href="#alias-predeterminados" aria-label="Permalink to &quot;Alias predeterminados&quot;">​</a></h1><p>Atajos esenciales para tareas diarias en el terminal.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Dotfiles banner"></p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Los alias predeterminados proporcionan atajos universales que simplifican operaciones comunes. Se definen en <code>default.aliases.sh</code> y se cargan automáticamente por chezmoi en todos los shells compatibles.</p><p>Estos atajos cubren utilidades generales, salida, diagnósticos de red, monitorización del sistema y navegación por el sistema de archivos.</p><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>da</code></td><td><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td>Mostrar fecha y hora actuales</td></tr><tr><td><code>p</code></td><td><code>pwd</code></td><td>Mostrar directorio actual</td></tr><tr><td><code>path</code></td><td><code>echo ${PATH//:/\\\\n}</code></td><td>Mostrar PATH en líneas separadas</td></tr><tr><td><code>r</code></td><td><code>reload</code></td><td>Recargar el shell</td></tr><tr><td><code>t</code></td><td><code>tail -f</code></td><td>Seguir salida de archivos en tiempo real</td></tr><tr><td><code>wk</code></td><td><code>date +%V</code></td><td>Mostrar número de semana</td></tr></tbody></table><h3 id="salida-y-apagado" tabindex="-1">Salida y apagado <a class="header-anchor" href="#salida-y-apagado" aria-label="Permalink to &quot;Salida y apagado&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>q</code></td><td><code>exit</code></td><td>Salir del shell</td></tr><tr><td><code>quit</code></td><td><code>exit</code></td><td>Salir del shell</td></tr><tr><td><code>bye</code></td><td><code>exit</code></td><td>Salir del shell</td></tr><tr><td><code>:q</code></td><td><code>exit</code></td><td>Salir del shell (estilo vim)</td></tr><tr><td><code>halt</code></td><td><code>sudo /sbin/halt</code></td><td>Apagar el sistema</td></tr><tr><td><code>poweroff</code></td><td><code>sudo /sbin/shutdown</code></td><td>Apagar el sistema</td></tr><tr><td><code>reboot</code></td><td><code>sudo /sbin/reboot</code></td><td>Reiniciar el sistema</td></tr></tbody></table><h3 id="historial" tabindex="-1">Historial <a class="header-anchor" href="#historial" aria-label="Permalink to &quot;Historial&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>h</code></td><td><code>history</code></td><td>Ver historial de comandos</td></tr><tr><td><code>history</code></td><td><code>fc -il 1</code></td><td>Historial con timestamps ISO 8601</td></tr></tbody></table><h3 id="red" tabindex="-1">Red <a class="header-anchor" href="#red" aria-label="Permalink to &quot;Red&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ifconfig</code></td><td><code>sudo ifconfig</code></td><td>Configurar interfaces de red</td></tr><tr><td><code>ipinfo</code></td><td><code>ipconfig getpacket en0</code></td><td>Obtener parámetros de red para en0</td></tr><tr><td><code>nls</code></td><td>`sudo lsof -i -P</td><td>grep LISTEN`</td></tr><tr><td><code>op</code></td><td><code>sudo lsof -i -P</code></td><td>Listar puertos abiertos</td></tr><tr><td><code>ping</code></td><td><code>ping -c 5</code></td><td>Ping con límite de 5 paquetes</td></tr><tr><td><code>ports</code></td><td><code>netstat -tulan</code></td><td>Listar puertos en escucha</td></tr></tbody></table><h3 id="monitorizacion-del-sistema" tabindex="-1">Monitorización del sistema <a class="header-anchor" href="#monitorizacion-del-sistema" aria-label="Permalink to &quot;Monitorización del sistema&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>top</code></td><td><code>sudo btop</code></td><td>Monitor de procesos interactivo</td></tr><tr><td><code>spd</code></td><td><code>sudo rm -rf /private/var/log/asl/*</code></td><td>Limpiar logs ASL</td></tr></tbody></table><h3 id="utilidades" tabindex="-1">Utilidades <a class="header-anchor" href="#utilidades" aria-label="Permalink to &quot;Utilidades&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ctf</code></td><td>`ls -1</td><td>wc -l`</td></tr><tr><td><code>qfind</code></td><td><code>find . -name</code></td><td>Búsqueda rápida de archivos</td></tr><tr><td><code>reload</code></td><td><code>exec $SHELL -l</code></td><td>Recargar el shell</td></tr><tr><td><code>wth</code></td><td><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td>Clima actual</td></tr></tbody></table>',19)])])}const u=e(i,[["render",r]]);export{m as __pageData,u as default};
